def _build_ai_context(uid, hid):
    parts=["You are GrihZen AI, an intelligent household management assistant embedded in the GrihZen app."]
    parts.append("You help users manage groceries, recipes, meal planning, shopping trips and household budgets.")
    try:
        inv=get_inventory(hid,uid)
        if not inv.empty:
            low=[r["name"] for _,r in inv.iterrows() if r.get("quantity",0)<=r.get("threshold",0)]
            parts.append(f"User has {len(inv)} inventory items. Low-stock items: {', '.join(low[:6]) if low else 'none'}.")
    except: pass
    try:
        vis=get_visits(uid,30)
        if not vis.empty:
            freq=vis["location_name"].value_counts().head(3)
            locs=", ".join([f"{n}({c}x)" for n,c in freq.items()])
            parts.append(f"Recent 30-day shopping: {len(vis)} trips. Top locations: {locs}.")
    except: pass
    try:
        recs=get_household_recipes(hid) if hid and hid>0 else []
        if recs: parts.append(f"Household recipe library: {len(recs)} recipes saved.")
    except: pass
    parts.append("Be concise, friendly, and practical. Use emoji sparingly.")
    return " ".join(parts)

def ai_chat(messages, uid, hid):
    if not _AI_CLIENT:
        return "⚠️ GrihZen AI is not configured. Set the ANTHROPIC_API_KEY environment variable and restart the app."
    system=_build_ai_context(uid,hid)
    resp=_AI_CLIENT.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=1024,
        system=system,
        messages=[{"role":m["role"],"content":m["content"]} for m in messages]
    )
    return resp.content[0].text

def calc_nutrition(ingredients):
    total={"cal":0,"pro":0,"carb":0,"fat":0,"fib":0}; vits=set()
    for iid,amt in ingredients.items():
        if iid in NUTRITION_DB:
            n=NUTRITION_DB[iid]; f=amt/100
            for k in ["cal","pro","carb","fat","fib"]: total[k]+=n[k]*f
            vits.update(n.get("vit",[]))
    total["vitamins"]=list(vits); return total

def nutrition_score(nut,srv=1):
    p={k:v/max(1,srv) for k,v in nut.items() if k!="vitamins"}
    s=min(30,(p.get("pro",0)/(DAILY_V["pro"]/3))*30)
    s+=min(20,(p.get("fib",0)/(DAILY_V["fib"]/3))*20)
    fp=p.get("fat",0)/(DAILY_V["fat"]/3)
    s+=20 if fp<1.2 else max(0,20-(fp-1.2)*10)
    s+=min(30,len(nut.get("vitamins",[]))*5)
    return min(100,int(s))

