# ── DATABASE ──────────────────────────────────────────────────────────────────
DB_PATH = os.path.join(os.path.dirname(os.path.abspath(__file__)), "grihzen_data", "grihzen.db")

def init_db():
    os.makedirs(os.path.dirname(DB_PATH), exist_ok=True)
    conn=sqlite3.connect(DB_PATH); c=conn.cursor()
    # Users
    c.execute("""CREATE TABLE IF NOT EXISTS users (
        id INTEGER PRIMARY KEY AUTOINCREMENT, username TEXT UNIQUE NOT NULL,
        display_name TEXT NOT NULL, password_hash TEXT NOT NULL, pin TEXT,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, last_login TIMESTAMP,
        daily_calories_goal INTEGER DEFAULT 2200, daily_protein_goal INTEGER DEFAULT 120)""")
    # Households (shared space like WhatsApp group)
    c.execute("""CREATE TABLE IF NOT EXISTS households (
        id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL,
        invite_code TEXT UNIQUE NOT NULL, created_by INTEGER,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        FOREIGN KEY(created_by) REFERENCES users(id))""")
    # Household members
    c.execute("""CREATE TABLE IF NOT EXISTS household_members (
        id INTEGER PRIMARY KEY AUTOINCREMENT, household_id INTEGER NOT NULL,
        user_id INTEGER NOT NULL, role TEXT DEFAULT 'member',
        joined_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        FOREIGN KEY(household_id) REFERENCES households(id),
        FOREIGN KEY(user_id) REFERENCES users(id))""")
    # Shared household recipes
    c.execute("""CREATE TABLE IF NOT EXISTS household_recipes (
        id INTEGER PRIMARY KEY AUTOINCREMENT, household_id INTEGER NOT NULL,
        recipe_id TEXT NOT NULL, name TEXT NOT NULL,
        category TEXT DEFAULT 'dinner', cuisine TEXT DEFAULT 'Indian',
        servings INTEGER DEFAULT 4, prep_hours REAL DEFAULT 0,
        cook_minutes INTEGER DEFAULT 30, ingredients TEXT DEFAULT '{}',
        nutrition TEXT DEFAULT '{}', is_imported INTEGER DEFAULT 0,
        added_by INTEGER, added_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        FOREIGN KEY(household_id) REFERENCES households(id))""")
    # Shared household locations
    c.execute("""CREATE TABLE IF NOT EXISTS household_locations (
        id INTEGER PRIMARY KEY AUTOINCREMENT, household_id INTEGER NOT NULL,
        location_id TEXT NOT NULL, name TEXT NOT NULL,
        address TEXT, lat REAL DEFAULT 0, lng REAL DEFAULT 0,
        location_type TEXT DEFAULT 'store', good_for TEXT DEFAULT '[]',
        avg_visit_duration INTEGER DEFAULT 30, price_rating REAL DEFAULT 3.0,
        quality_rating REAL DEFAULT 3.0, added_by INTEGER,
        FOREIGN KEY(household_id) REFERENCES households(id))""")
    # Personal inventory (per user)
    c.execute("""CREATE TABLE IF NOT EXISTS inventory (
        id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER NOT NULL,
        item_id TEXT NOT NULL, name TEXT NOT NULL,
        quantity REAL DEFAULT 0, unit TEXT DEFAULT 'units',
        threshold REAL DEFAULT 1, category TEXT DEFAULT 'general',
        calories_per_100g REAL DEFAULT 0, protein_per_100g REAL DEFAULT 0,
        carbs_per_100g REAL DEFAULT 0, fat_per_100g REAL DEFAULT 0,
        fiber_per_100g REAL DEFAULT 0, vitamins TEXT DEFAULT '[]',
        FOREIGN KEY(user_id) REFERENCES users(id))""")
    # Personal visits (per user)
    c.execute("""CREATE TABLE IF NOT EXISTS visits (
        id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER NOT NULL,
        location_id TEXT, location_type TEXT, location_name TEXT,
        visited_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        FOREIGN KEY(user_id) REFERENCES users(id))""")
    # ── DATABASE MIGRATIONS ──
    migrations = [
        "ALTER TABLE inventory ADD COLUMN household_id INTEGER",
        "ALTER TABLE inventory ADD COLUMN last_updated_by INTEGER",
    ]
    for m in migrations:
        try: c.execute(m)
        except: pass
    conn.commit(); conn.close()

def get_db(): return sqlite3.connect(DB_PATH)
def hash_pw(pw): return hashlib.sha256(pw.encode()).hexdigest()
def gen_invite_code(): return secrets.token_urlsafe(6).upper()

# ── AUTH ──────────────────────────────────────────────────────────────────────
def create_user(username, display_name, password, pin=None):
    try:
        conn=get_db(); c=conn.cursor()
        c.execute("INSERT INTO users (username,display_name,password_hash,pin) VALUES (?,?,?,?)",
                  (username.lower(),display_name,hash_pw(password),hash_pw(pin) if pin else None))
        conn.commit(); conn.close(); return True
    except sqlite3.IntegrityError: return False

def authenticate_user(username, password):
    conn=get_db(); c=conn.cursor()
    c.execute("SELECT id,username,display_name FROM users WHERE username=? AND password_hash=?",
              (username.lower(),hash_pw(password)))
    user=c.fetchone()
    if user:
        c.execute("UPDATE users SET last_login=CURRENT_TIMESTAMP WHERE id=?",(user[0],)); conn.commit()
    conn.close(); return user

def get_user(uid):
    conn=get_db(); c=conn.cursor(); c.execute("SELECT * FROM users WHERE id=?",(uid,))
    row=c.fetchone(); conn.close()
    if row: return dict(zip(["id","username","display_name","password_hash","pin","created_at","last_login","daily_calories_goal","daily_protein_goal"],row))
    return None

def reset_password_with_pin(username, pin, new_password):
    conn=get_db(); c=conn.cursor()
    c.execute("SELECT id,pin FROM users WHERE username=?",(username.lower(),))
    row=c.fetchone()
    if not row: conn.close(); return "no_user"
    if not row[1]: conn.close(); return "no_pin"
    if row[1]!=hash_pw(pin): conn.close(); return "wrong_pin"
    c.execute("UPDATE users SET password_hash=? WHERE id=?",(hash_pw(new_password),row[0]))
    conn.commit(); conn.close(); return "ok"

# ── HOUSEHOLD ─────────────────────────────────────────────────────────────────
def create_household(name, user_id):
    code=gen_invite_code()
    conn=get_db(); c=conn.cursor()
    c.execute("INSERT INTO households (name,invite_code,created_by) VALUES (?,?,?)",(name,code,user_id))
    hid=c.lastrowid
    c.execute("INSERT INTO household_members (household_id,user_id,role) VALUES (?,?,?)",(hid,user_id,"admin"))
    conn.commit(); conn.close(); return hid, code

def join_household(invite_code, user_id):
    conn=get_db(); c=conn.cursor()
    c.execute("SELECT id FROM households WHERE invite_code=?",(invite_code.upper(),))
    h=c.fetchone()
    if not h: conn.close(); return None
    # Check not already member
    c.execute("SELECT id FROM household_members WHERE household_id=? AND user_id=?",(h[0],user_id))
    if c.fetchone(): conn.close(); return h[0]
    c.execute("INSERT INTO household_members (household_id,user_id) VALUES (?,?)",(h[0],user_id))
    conn.commit(); conn.close(); return h[0]

def get_user_household(user_id):
    conn=get_db(); c=conn.cursor()
    c.execute("""SELECT h.id,h.name,h.invite_code,hm.role FROM households h
                 JOIN household_members hm ON h.id=hm.household_id
                 WHERE hm.user_id=? ORDER BY hm.joined_at LIMIT 1""",(user_id,))
    row=c.fetchone(); conn.close()
    if row: return {"id":row[0],"name":row[1],"invite_code":row[2],"role":row[3]}
    return None

def get_household_members(household_id):
    conn=get_db()
    df=pd.read_sql_query("""SELECT u.display_name,u.username,hm.role,hm.joined_at
                            FROM household_members hm JOIN users u ON hm.user_id=u.id
                            WHERE hm.household_id=?""",conn,params=(household_id,))
    conn.close(); return df

# ── HOUSEHOLD RECIPES ─────────────────────────────────────────────────────────
def get_household_recipes(hid, category=None):
    conn=get_db()
    q="SELECT * FROM household_recipes WHERE household_id=?"
    params=(hid,)
    if category:
        q+=" AND category=?"; params=(hid,category)
    df=pd.read_sql_query(q,conn,params=params); conn.close(); return df

def add_household_recipe(hid, recipe_id, name, cat, cuisine, servings, prep, cook, ingredients, user_id, is_imported=0):
    nut=calc_nutrition(ingredients)
    conn=get_db(); c=conn.cursor()
    c.execute("""INSERT INTO household_recipes
        (household_id,recipe_id,name,category,cuisine,servings,prep_hours,cook_minutes,ingredients,nutrition,is_imported,added_by)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?)""",
        (hid,recipe_id,name,cat,cuisine,servings,prep,cook,json.dumps(ingredients),json.dumps(nut),is_imported,user_id))
    conn.commit(); conn.close()

def delete_household_recipe(hid, recipe_id):
    conn=get_db(); c=conn.cursor()
    c.execute("DELETE FROM household_recipes WHERE household_id=? AND recipe_id=?",(hid,recipe_id)); conn.commit(); conn.close()

