# ── PERSONAL INVENTORY ────────────────────────────────────────────────────────
def get_inventory(hid, uid=None):
    """Get HOUSEHOLD inventory. Falls back gracefully if column missing."""
    conn = get_db(); c = conn.cursor()
    # Ensure household_id column exists (migration safety)
    try:
        c.execute("ALTER TABLE inventory ADD COLUMN household_id INTEGER")
        c.execute("ALTER TABLE inventory ADD COLUMN last_updated_by INTEGER")
        conn.commit()
    except: pass
    # Assign existing personal items to household if needed
    if hid and hid > 0 and uid:
        try:
            c.execute("UPDATE inventory SET household_id=? WHERE user_id=? AND (household_id IS NULL OR household_id=0)",
                      (hid, uid))
            conn.commit()
        except: pass
    conn.close()
    # Now query
    conn = get_db()
    try:
        if hid and hid > 0:
            df = pd.read_sql_query(
                "SELECT * FROM inventory WHERE household_id=? ORDER BY category,name",
                conn, params=(hid,))
        else:
            df = pd.read_sql_query(
                "SELECT * FROM inventory WHERE user_id=? ORDER BY category,name",
                conn, params=(uid,))
    except Exception as e:
        # Fallback: return empty if any error
        df = pd.DataFrame()
    conn.close()
    return df

def add_inventory_item(hid, uid, iid, name, qty, unit, thresh, cat):
    n=NUTRITION_DB.get(iid,{}); conn=get_db(); c=conn.cursor()
    c.execute("""INSERT INTO inventory
        (household_id,user_id,item_id,name,quantity,unit,threshold,category,
         calories_per_100g,protein_per_100g,carbs_per_100g,fat_per_100g,fiber_per_100g,vitamins)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
        (hid,uid,iid,name,qty,unit,thresh,cat,n.get("cal",0),n.get("pro",0),n.get("carb",0),n.get("fat",0),n.get("fib",0),json.dumps(n.get("vit",[]))))

def update_inventory(hid,uid,iid,qty=None,thresh=None):
    """Update HOUSEHOLD inventory item"""
    conn=get_db(); c=conn.cursor()
    if qty is not None: c.execute("UPDATE inventory SET quantity=?,last_updated_by=? WHERE household_id=? AND item_id=?",(qty,uid,hid,iid))
    if thresh is not None: c.execute("UPDATE inventory SET threshold=? WHERE household_id=? AND item_id=?",(thresh,hid,iid))
    conn.commit(); conn.close()
def delete_inventory_item(hid,iid):
    """Remove item from HOUSEHOLD inventory"""
    conn=get_db(); c=conn.cursor()
    c.execute("DELETE FROM inventory WHERE household_id=? AND item_id=?",(hid,iid))
    conn.commit(); conn.close()
    conn=get_db(); df=pd.read_sql_query("SELECT * FROM visits WHERE user_id=? AND visited_at >= datetime('now',?)",conn,params=(uid,f'-{days} days')); conn.close(); return df


def get_visits(uid, days=30):
    """Get personal visit history for a user"""
    conn = get_db()
    try:
        df = pd.read_sql_query(
            "SELECT * FROM visits WHERE user_id=? AND visited_at >= datetime('now',?) ORDER BY visited_at DESC",
            conn, params=(uid, f'-{days} days'))
    except:
        df = pd.DataFrame()
    conn.close()
    if not df.empty and 'visited_at' in df.columns:
        df['visited_at'] = pd.to_datetime(df['visited_at'])
        df['day_of_week'] = df['visited_at'].dt.dayofweek
        df['hour'] = df['visited_at'].dt.hour
        df['is_weekend'] = df['day_of_week'].isin([5, 6]).astype(int)
        df['month'] = df['visited_at'].dt.month
    return df

def log_visit(uid,lid,lt,ln):
    conn=get_db(); c=conn.cursor(); c.execute("INSERT INTO visits (user_id,location_id,location_type,location_name) VALUES (?,?,?,?)",(uid,lid,lt,ln)); conn.commit(); conn.close()

# ── UTILS ─────────────────────────────────────────────────────────────────────
def haversine(la1,lo1,la2,lo2):
    R=3959; dl=math.radians(la2-la1); dlo=math.radians(lo2-lo1)
    a=math.sin(dl/2)**2+math.cos(math.radians(la1))*math.cos(math.radians(la2))*math.sin(dlo/2)**2
    return R*2*math.asin(math.sqrt(a))
def est_time(d): return max(5,int(d*2.5+3))
def greeting():
    h=datetime.now().hour
    return "Good Morning" if h<12 else "Good Afternoon" if h<17 else "Good Evening" if h<21 else "Good Night"

# ── ROUTE ALGORITHMS ──────────────────────────────────────────────────────────
def nearest_neighbor(locs,start,end=None):
    t0=time.time(); unv=list(locs); route=[start]; cur=start
    while unv:
        near=min(unv,key=lambda l:haversine(cur["lat"],cur["lng"],l["lat"],l["lng"]))
        route.append(near); unv.remove(near); cur=near
    if end: route.append(end)
    d=sum(haversine(route[i]["lat"],route[i]["lng"],route[i+1]["lat"],route[i+1]["lng"]) for i in range(len(route)-1))
    return route,d,(time.time()-t0)*1000

def two_opt(locs,start,end=None):
    t0=time.time(); route,d,_=nearest_neighbor(locs,start,end)
    stops=route[1:-1] if end else route[1:]; improved=True
    while improved:
        improved=False
        for i in range(len(stops)-1):
            for j in range(i+1,len(stops)):
                ns=stops[:i]+stops[i:j+1][::-1]+stops[j+1:]; nr=[start]+ns+([end] if end else [])
                nd=sum(haversine(nr[k]["lat"],nr[k]["lng"],nr[k+1]["lat"],nr[k+1]["lng"]) for k in range(len(nr)-1))
                if nd<d: d,stops,improved=nd,ns,True
    return [start]+stops+([end] if end else []),d,(time.time()-t0)*1000

def sim_anneal(locs,start,end=None,T=1000,cool=0.995,iters=500):
    t0=time.time(); route,d,_=nearest_neighbor(locs,start,end)
    stops=list(route[1:-1] if end else route[1:]); best,bd=stops[:],d
    for _ in range(iters):
        if len(stops)<2: break
        i,j=sorted(random.sample(range(len(stops)),2)); ns=stops[:i]+stops[i:j+1][::-1]+stops[j+1:]
        nr=[start]+ns+([end] if end else [])
        nd=sum(haversine(nr[k]["lat"],nr[k]["lng"],nr[k+1]["lat"],nr[k+1]["lng"]) for k in range(len(nr)-1))
        if nd<d or random.random()<math.exp(-(nd-d)/T): stops,d=ns,nd
        if d<bd: bd,best=d,stops[:]
        T*=cool
    return [start]+best+([end] if end else []),bd,(time.time()-t0)*1000

def genetic(locs,start,end=None,pop=30,gens=100):
    t0=time.time()
    if not locs: return [start]+([end] if end else []),0,(time.time()-t0)*1000
    def td(p):
        r=[start]+list(p)+([end] if end else [])
        return sum(haversine(r[i]["lat"],r[i]["lng"],r[i+1]["lat"],r[i+1]["lng"]) for i in range(len(r)-1))
    ls=list(locs); population=[random.sample(ls,len(ls)) for _ in range(pop)]
    for _ in range(gens):
        population.sort(key=td); ng=population[:5]
        while len(ng)<pop:
            p1,p2=random.choices(population[:15],k=2); c1,c2=sorted(random.sample(range(len(ls)),2))
            child=p1[c1:c2]+[x for x in p2 if x not in p1[c1:c2]]
            if random.random()<0.1 and len(child)>1:
                i,j=random.sample(range(len(child)),2); child[i],child[j]=child[j],child[i]
            ng.append(child)
        population=ng
    best=min(population,key=td); return [start]+best+([end] if end else []),td(best),(time.time()-t0)*1000

