    st.markdown(f'<div class="gz-household-card"><div style="font-family:Outfit,sans-serif;font-size:1.3rem;font-weight:800;margin-bottom:.5rem;">🏠 What is a Household?</div><div style="opacity:.8;font-size:.875rem;line-height:1.6;">Like a WhatsApp Group for your home:<br>✅ <b>Shared:</b> Recipes, Stores & Locations<br>🔒 <b>Personal:</b> Inventory levels, Routes, Analytics<br>👥 <b>Members:</b> Invite family with a code</div></div>',unsafe_allow_html=True)
