    if display_recipes.empty:
        st.markdown(f'<div class="gz-card" style="text-align:center;padding:3rem;color:{C["gray_400"]};"><div style="font-size:3rem;">🍽️</div><div style="font-weight:600;margin:.5rem 0;">No recipes yet!</div><div>Import from the library or add your own above</div></div>',unsafe_allow_html=True)
        return

    for _,row in display_recipes.iterrows():
        ings=json.loads(row["ingredients"]) if row["ingredients"] else {}
        nut=json.loads(row["nutrition"]) if row["nutrition"] else {}
